from qiskit_ibm_runtime import EstimatorOptions

candidates = {"A": 2, "B": 3, "C": 5, "D": -1}
evidence = {}
proven = []
for k, val in candidates.items():
    try:
        o = EstimatorOptions()
        o.resilience_level = val
        evidence[k] = f"resilience_level = {val} accepted (EstimatorV2 supports levels 0, 1, 2)"
        proven.append(k)
    except Exception as e:
        evidence[k] = f"resilience_level = {val} raises {type(e).__name__}: value must be an integer in the range 0..2"
emit_verdict({"answer": proven, "evidence": evidence, "observed": {}})
